import{_ as a,o as n,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Packaging with Cargo","description":"Preparing the agent for distribution through crates.io and cargo install, including Cargo.toml metadata, feature flags, and binary size optimization.","frontmatter":{"title":"Packaging with Cargo","description":"Preparing the agent for distribution through crates.io and cargo install, including Cargo.toml metadata, feature flags, and binary size optimization."},"headers":[],"relativePath":"learn/project/15-production-polish/05-packaging-with-cargo.md","filePath":"learn/project/15-production-polish/05-packaging-with-cargo.md"}'),p={name:"learn/project/15-production-polish/05-packaging-with-cargo.md"};function t(e,s,c,r,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="packaging-with-cargo" tabindex="-1">Packaging with Cargo <a class="header-anchor" href="#packaging-with-cargo" aria-label="Permalink to &quot;Packaging with Cargo&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to configure Cargo.toml metadata for publishing to crates.io including categories and keywords</li><li>How to use Cargo feature flags to make optional dependencies and provider support toggleable</li><li>Techniques for optimizing binary size with LTO, strip, and codegen-units settings</li></ul></blockquote><p>Your agent works. It has error recovery, structured logging, configuration management, and a proper CLI interface. Now it is time to package it so other people can install it. Rust&#39;s Cargo makes this remarkably straightforward -- <code>cargo install</code> is the Rust equivalent of <code>pip install</code>, and crates.io is the equivalent of PyPI. But getting the packaging right takes attention to metadata, feature flags, and binary optimization.</p><h2 id="preparing-cargo-toml-for-publishing" tabindex="-1">Preparing Cargo.toml for Publishing <a class="header-anchor" href="#preparing-cargo-toml-for-publishing" aria-label="Permalink to &quot;Preparing Cargo.toml for Publishing&quot;">​</a></h2><p>A publishable <code>Cargo.toml</code> needs more metadata than a development project. Here is a complete example:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">package</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.1.0&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">edition </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;2021&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">authors </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;Your Name &lt;you@example.com&gt;&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">description </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;A CLI coding agent powered by LLMs&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">license </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;MIT&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">repository </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://github.com/yourusername/agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">homepage </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://github.com/yourusername/agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">documentation </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://docs.rs/agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">readme </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;README.md&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">keywords </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;cli&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;llm&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;coding&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;ai&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">categories </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command-line-utilities&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;development-tools&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">exclude </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;tests/fixtures/**&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;.github/**&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;docs/**&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;*.excalidraw&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Ensure the binary name is what users expect</span></span>
<span class="line"><span style="color:#9399B2;">[[</span><span style="color:#CDD6F4;">bin</span><span style="color:#9399B2;">]]</span></span>
<span class="line"><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">path </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">tokio </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;full&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;json&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;stream&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">serde </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;derive&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">serde_json </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">clap </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;4&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;derive&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;env&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">tracing </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.1&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">tracing-subscriber </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.3&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;env-filter&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;json&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">anyhow </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">toml </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.8&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">dirs </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;5&quot;</span></span></code></pre></div><p>The <code>exclude</code> field keeps test fixtures, CI configuration, and documentation sources out of the published crate. This reduces download size and avoids including files that are irrelevant to installation.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you configure packaging metadata in <code>pyproject.toml</code> (or the older <code>setup.py</code>). Rust&#39;s <code>Cargo.toml</code> serves the same purpose but with stricter conventions. Where Python packages need a <code>MANIFEST.in</code> to control what goes into a distribution, Cargo uses the <code>exclude</code> and <code>include</code> fields. The <code>keywords</code> and <code>categories</code> fields in Cargo map to classifiers in PyPI, helping users discover your package.</p></div><h2 id="feature-flags-for-optional-dependencies" tabindex="-1">Feature Flags for Optional Dependencies <a class="header-anchor" href="#feature-flags-for-optional-dependencies" aria-label="Permalink to &quot;Feature Flags for Optional Dependencies&quot;">​</a></h2><p>Not every user needs every LLM provider. Feature flags let users compile only what they need, reducing binary size and avoiding unnecessary dependencies.</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">features</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">default </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;anthropic&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;markdown-rendering&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># LLM Providers</span></span>
<span class="line"><span style="color:#CDD6F4;">anthropic </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:reqwest&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">openai </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:reqwest&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">ollama </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:reqwest&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># UI features</span></span>
<span class="line"><span style="color:#CDD6F4;">markdown-rendering </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:termimad&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">syntax-highlighting </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:syntect&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># All features for development</span></span>
<span class="line"><span style="color:#CDD6F4;">full </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;anthropic&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;openai&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;ollama&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;markdown-rendering&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;syntax-highlighting&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;json&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;stream&quot;</span><span style="color:#9399B2;">],</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">termimad </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.30&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">syntect </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;5&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>In your code, you conditionally compile provider support:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> create_provider</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">name</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> config</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">ProviderConfig</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> AgentError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> name </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;anthropic&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;anthropic&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Box</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">AnthropicProvider</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">config</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">)),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;openai&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;openai&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Box</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">OpenAiProvider</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">config</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">)),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;ollama&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;ollama&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Box</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">OllamaProvider</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">config</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">)),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">        other </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> available </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> available_providers</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            Err</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">AgentError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ConfigInvalid</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">                field</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;provider.name&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#CDD6F4;">                message</span><span style="color:#94E2D5;">:</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#A6E3A1;">                    &quot;Provider &#39;</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">other</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&#39; is not available. Compiled providers: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">. \\</span></span>
<span class="line"><span style="color:#A6E3A1;">                     Rebuild with the appropriate feature flag to enable other providers.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">                    available</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;, &quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">                ),</span></span>
<span class="line"><span style="color:#9399B2;">            })</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> available_providers</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">&amp;</span><span style="color:#9399B2;">&#39;</span><span style="color:#89B4FA;font-style:italic;">static</span><span style="color:#F9E2AF;font-style:italic;"> str</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> providers </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;anthropic&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CDD6F4;">    providers</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;anthropic&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;openai&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CDD6F4;">    providers</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;openai&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;ollama&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CDD6F4;">    providers</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ollama&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    providers</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Users install with specific features:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Default features (anthropic + markdown)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Only OpenAI support, no markdown rendering</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> agent</span><span style="color:#A6E3A1;"> --no-default-features</span><span style="color:#A6E3A1;"> --features</span><span style="color:#A6E3A1;"> openai</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Everything</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> agent</span><span style="color:#A6E3A1;"> --features</span><span style="color:#A6E3A1;"> full</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code bundles platform-specific binaries within an npm package, sidestepping the crates.io distribution model entirely. OpenCode publishes to Go&#39;s module system. For Rust CLI tools, the <code>ripgrep</code> project is an excellent model -- it uses feature flags extensively to make optional features like PCRE2 regex support toggleable, and its <code>Cargo.toml</code> metadata is meticulously maintained for clean crates.io publishing.</p></div><h2 id="optimizing-binary-size" tabindex="-1">Optimizing Binary Size <a class="header-anchor" href="#optimizing-binary-size" aria-label="Permalink to &quot;Optimizing Binary Size&quot;">​</a></h2><p>Rust binaries can be large. A debug build of a moderately complex application might be 50MB or more. Release builds are much smaller, but you can optimize further.</p><p>Add these settings to your <code>Cargo.toml</code>:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">profile.release</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Link-Time Optimization: enables cross-crate optimizations</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># &quot;fat&quot; is slower to compile but produces smaller, faster binaries</span></span>
<span class="line"><span style="color:#CDD6F4;">lto </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;fat&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Use a single codegen unit for maximum optimization</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># (default is 16; 1 = slower compile, better optimization)</span></span>
<span class="line"><span style="color:#CDD6F4;">codegen_units </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Strip debug symbols from the binary</span></span>
<span class="line"><span style="color:#CDD6F4;">strip </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;symbols&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Optimize for size with some speed tradeoff (optional)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># opt-level = &quot;s&quot;    # optimize for size</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># opt-level = &quot;z&quot;    # aggressively optimize for size</span></span>
<span class="line"><span style="color:#CDD6F4;">opt-level </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 3</span><span style="color:#6C7086;font-style:italic;">        # optimize for speed (default for release)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Abort on panic instead of unwinding (smaller binary, no backtraces)</span></span>
<span class="line"><span style="color:#CDD6F4;">panic </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;abort&quot;</span></span></code></pre></div><p>Here is the impact of each setting on a typical agent binary:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Size Impact</th><th>Compile Time Impact</th></tr></thead><tbody><tr><td>Default release</td><td>Baseline (~15MB)</td><td>Baseline</td></tr><tr><td><code>lto = &quot;fat&quot;</code></td><td>-20-30%</td><td>+50-100%</td></tr><tr><td><code>codegen_units = 1</code></td><td>-5-10%</td><td>+20-30%</td></tr><tr><td><code>strip = &quot;symbols&quot;</code></td><td>-30-50%</td><td>None</td></tr><tr><td><code>panic = &quot;abort&quot;</code></td><td>-5-10%</td><td>None</td></tr><tr><td>All combined</td><td>-50-70% (~5MB)</td><td>+100-150%</td></tr></tbody></table><p>For development builds, you want fast compile times, so leave these settings in the <code>[profile.release]</code> section only.</p><details class="details custom-block"><summary>How LTO works</summary><p>Link-Time Optimization lets the compiler optimize across crate boundaries. Normally, each crate is compiled independently and linked together at the end. With LTO, the linker sees the entire program and can inline functions across crate boundaries, eliminate dead code more aggressively, and perform whole-program optimizations that are impossible with separate compilation.</p></details><h2 id="building-for-release" tabindex="-1">Building for Release <a class="header-anchor" href="#building-for-release" aria-label="Permalink to &quot;Building for Release&quot;">​</a></h2><p>The build command is straightforward:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Standard release build</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build with specific features</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --features</span><span style="color:#A6E3A1;"> full</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check the binary size</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ls</span><span style="color:#A6E3A1;"> -lh</span><span style="color:#A6E3A1;"> target/release/agent</span></span></code></pre></div><p>You can further reduce size with <code>upx</code>, a binary packer:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install upx</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> upx</span><span style="color:#6C7086;font-style:italic;">  # macOS</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># or: apt install upx-ucl  # Ubuntu</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Compress the binary (typically 50-70% size reduction)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">upx</span><span style="color:#A6E3A1;"> --best</span><span style="color:#A6E3A1;"> target/release/agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify it still works</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">./target/release/agent</span><span style="color:#A6E3A1;"> --version</span></span></code></pre></div><h2 id="adding-a-build-script-for-version-information" tabindex="-1">Adding a Build Script for Version Information <a class="header-anchor" href="#adding-a-build-script-for-version-information" aria-label="Permalink to &quot;Adding a Build Script for Version Information&quot;">​</a></h2><p>A build script can embed Git information into the binary at compile time:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// build.rs (in the project root, next to Cargo.toml)</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Embed the git commit hash</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Command</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;git&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">args</span><span style="color:#9399B2;">([</span><span style="color:#A6E3A1;">&quot;rev-parse&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;--short&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;HEAD&quot;</span><span style="color:#9399B2;">])</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> output </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> git_hash </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">trim</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;cargo:rustc-env=GIT_HASH=</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">git_hash</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span><span style="color:#CBA6F7;"> else</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;cargo:rustc-env=GIT_HASH=unknown&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Embed the build timestamp</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> now </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> chrono</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Utc</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">now</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">format</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;%Y-%m-%d&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;cargo:rustc-env=BUILD_DATE=</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">now</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Re-run if git HEAD changes</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;cargo:rerun-if-changed=.git/HEAD&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Use the embedded values in your CLI version output:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> clap</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Parser</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Parser</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">command</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    version </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> format</span><span style="color:#94E2D5;">!</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> (</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">; built </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        env</span><span style="color:#94E2D5;">!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;CARGO_PKG_VERSION&quot;</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        env</span><span style="color:#94E2D5;">!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;GIT_HASH&quot;</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        env</span><span style="color:#94E2D5;">!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;BUILD_DATE&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">    ),</span></span>
<span class="line"><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Cli</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // ... fields</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Now <code>agent --version</code> shows:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>agent 0.1.0 (a3f2b1c; built 2026-03-16)</span></span></code></pre></div><h2 id="publishing-to-crates-io" tabindex="-1">Publishing to crates.io <a class="header-anchor" href="#publishing-to-crates-io" aria-label="Permalink to &quot;Publishing to crates.io&quot;">​</a></h2><p>Before publishing, verify everything is in order:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Dry run: check what would be published</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> publish</span><span style="color:#A6E3A1;"> --dry-run</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check the package contents</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> package</span><span style="color:#A6E3A1;"> --list</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run all tests</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Publish (requires a crates.io account and API token)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> publish</span></span></code></pre></div><p>After publishing, anyone can install your agent with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> agent</span></span></code></pre></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Fill in all metadata fields in <code>Cargo.toml</code> (description, license, repository, keywords, categories) before publishing -- these are not optional for a professional package.</li><li>Use feature flags to make provider support and optional UI features toggleable, letting users install only what they need and reducing binary size for minimal installations.</li><li>Apply <code>lto = &quot;fat&quot;</code>, <code>codegen_units = 1</code>, <code>strip = &quot;symbols&quot;</code>, and <code>panic = &quot;abort&quot;</code> in <code>[profile.release]</code> to reduce binary size by 50-70% compared to a default release build.</li><li>Use a <code>build.rs</code> script to embed Git commit hash and build date into the binary, making <code>--version</code> output useful for debugging and support.</li><li>Always run <code>cargo publish --dry-run</code> before actually publishing to catch metadata issues, missing files, or accidental inclusion of large test fixtures.</li></ul>`,43)])])}const A=a(p,[["render",t]]);export{d as __pageData,A as default};
